package org.jsoup.nodes;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/org/jsoup/nodes/requirement.feature",
    glue = "org.jsoup.nodes.steps"
)
public class CucumberTest {
}

package org.jsoup.nodes.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.When;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.junit.Assert;

public class StepDefs {

    private String html;
    private Document document;

    @Given("the HTML source {string}")
    public void the_html_source(String html) {
        this.html = html;
    }

    @When("the document is parsed")
    public void the_document_is_parsed() {
        try {
            this.document = Jsoup.parse(html);
        } catch (Exception e) {
            e.printStackTrace();
            Assert.fail("Exception thrown during parsing: " + e.getMessage());
        }
    }

    @Then("the document body text should be {string}")
    public void the_document_body_text_should_be(String expectedText) {
        Assert.assertNotNull("Document should not be null", document);
        String actualText = document.body().text();
        Assert.assertEquals(expectedText, actualText);
    }
}
